using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver — knows about any type.
var webOptions = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns JsonTypeInfo<T> directly (no cast needed).
JsonTypeInfo<Person> personInfo = webOptions.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person>  →  Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing.
//    With the web defaults (reflection resolver) this succeeds for any type:
if (webOptions.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded  →  {found!.Type.Name}");
}

// Now show TryGetTypeInfo returning false:
// Use a source-gen context that only knows about Person, not about int[].
var strictOptions = new JsonSerializerOptions
{
    TypeInfoResolver = PersonOnlyContext.Default
};

if (strictOptions.TryGetTypeInfo<int[]>(out JsonTypeInfo<int[]>? arrayInfo))
{
    Console.WriteLine($"TryGetTypeInfo<int[]> succeeded (unexpected)");
}
else
{
    Console.WriteLine("TryGetTypeInfo<int[]> returned false — metadata not available (no exception!)");
}

// --- Types ----------------------------------------------------------------

public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
public partial class PersonOnlyContext : JsonSerializerContext;

